import * as utils from '../lib/utils.js';

const createDeferred = () => {
    let resolve;
    let reject;
    const promise = new Promise((res, rej) => {
        resolve = res;
        reject = rej;
    });
    return { promise, resolve, reject };
};

const gui_cache_keys = [
    'has_set_default_app_user_permissions',
    'window_sidebar_width',
    'sidebar_items',
    'menubar_style',
    'user_preferences.auto_arrange_desktop',
    'user_preferences.show_hidden_files',
    'user_preferences.language',
    'user_preferences.clock_visible',
    'toolbar_auto_hide_enabled',
    'has_seen_welcome_window',
    'desktop_item_positions',
    'desktop_icons_hidden',
    'taskbar_position',
    'has_seen_toolbar_animation',
];

const isObject = (value) => value !== null && typeof value === 'object' && !Array.isArray(value);
const isOptConfigShorthand = (value) => isObject(value) && Object.prototype.hasOwnProperty.call(value, 'appUuid');
const isBatchSetItem = (value) => isObject(value) && Object.prototype.hasOwnProperty.call(value, 'key');

class KV {
    MAX_KEY_SIZE = 1024;
    MAX_VALUE_SIZE = 399 * 1024;

    /**
     * Creates a new instance with the given authentication token, API origin, and app ID,
     *
     * @class
     * @param {string} authToken - Token used to authenticate the user.
     * @param {string} APIOrigin - Origin of the API server. Used to build the API endpoint URLs.
     * @param {string} appID - ID of the app to use.
     */
    constructor (puter) {
        this.puter = puter;
        this.authToken = puter.authToken;
        this.APIOrigin = puter.APIOrigin;
        this.appID = puter.appID;

        this.gui_cached = createDeferred();
        this.gui_cache_init = createDeferred();
        (async () => {
            await this.gui_cache_init.promise;
            this.gui_cache_init = null;
            const resp = await fetch(`${this.APIOrigin}/drivers/call`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'text/plain;actually=json',
                },
                body: JSON.stringify({
                    interface: 'puter-kvstore',
                    method: 'get',
                    args: {
                        key: gui_cache_keys,
                    },
                    auth_token: this.authToken,
                }),
            });
            const arr_values = await resp.json();
            if ( ! Array.isArray(arr_values?.result) ) {
                this.gui_cached.resolve({});
                setTimeout(() => {
                    this.gui_cached = null;
                }, 4000);
                return;
            }
            const obj = {};
            for ( let i = 0; i < gui_cache_keys.length; i++ ) {
                obj[gui_cache_keys[i]] = arr_values.result[i];
            }
            this.gui_cached.resolve(obj);
            setTimeout(() => {
                this.gui_cached = null;
            }, 4000);
        })();
    }

    /**
     * Sets a new authentication token.
     *
     * @param {string} authToken - The new authentication token.
     * @memberof [KV]
     * @returns {void}
     */
    setAuthToken (authToken) {
        this.authToken = authToken;
    }

    /**
     * Sets the API origin.
     *
     * @param {string} APIOrigin - The new API origin.
     * @memberof [KV]
     * @returns {void}
     */
    setAPIOrigin (APIOrigin) {
        this.APIOrigin = APIOrigin;
    }

    /**
     * @typedef {function(key: string, value: any, expireAt?: number, optConfig?: object): Promise<boolean>} SetFunction
     * Resolves to 'true' on success, or rejects with an error on failure.
     * @param {string} key - Cannot be undefined or null. Cannot be larger than 1KB.
     * @param {any} value - Cannot be larger than 399KB.
     * @param {number} [expireAt] - Optional expiration time for the key. Note that clients with a clock that is not in sync with the server may experience issues with this method.
     * @param {object} [optConfig] - Optional driver call config, e.g. `{ appUuid: 'uuid' }`.
     * @memberof KV
     */

    /** @type {SetFunction} */
    set = async (...args) => {
        if ( Array.isArray(args[0]) ) {
            const items = args[0];
            const rest = args.slice(1);

            let optConfig;
            let success;
            let error;

            if ( rest[0] === undefined ) {
                rest.shift();
            }

            if ( isObject(rest[0]) ) {
                optConfig = rest.shift();
            }

            if ( typeof rest[0] === 'function' ) {
                success = rest.shift();
            }
            if ( typeof rest[0] === 'function' ) {
                error = rest.shift();
            }

            return await this.setBatch_({ items, optConfig, success, error });
        }

        if ( args.length === 1 && isObject(args[0]) ) {
            if ( Array.isArray(args[0].items) ) {
                return await this.setBatch_(args[0]);
            }
            return await this.set_(args[0]);
        }

        const key = args[0];
        const value = args[1];
        const rest = args.slice(2);

        let expireAt;
        let optConfig;
        let success;
        let error;

        if ( typeof rest[0] === 'number' || rest[0] === null ) {
            expireAt = rest.shift();
        }

        if ( rest[0] === undefined ) {
            rest.shift();
        }

        if ( isObject(rest[0]) ) {
            optConfig = rest.shift();
        }

        if ( typeof rest[0] === 'function' ) {
            success = rest.shift();
        }
        if ( typeof rest[0] === 'function' ) {
            error = rest.shift();
        }

        return await this.set_({ key, value, expireAt, optConfig, success, error });
    };

    set_ = utils.make_driver_method(['key', 'value', 'expireAt'], 'puter-kvstore', undefined, 'set', {
        /**
         *
         * @param {object} args
         * @param {string} args.key
         * @param {any} args.value
         * @param {number} [args.expireAt]
         * @memberof [KV]
         * @returns
         */
        preprocess: (args) => {
            // key cannot be undefined or null
            if ( args.key === undefined || args.key === null ) {
                throw { message: 'Key cannot be undefined', code: 'key_undefined' };
            }
            // key size cannot be larger than MAX_KEY_SIZE
            if ( args.key.length > this.MAX_KEY_SIZE ) {
                throw { message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' };
            }
            // value size cannot be larger than MAX_VALUE_SIZE
            if ( args.value && args.value.length > this.MAX_VALUE_SIZE ) {
                throw { message: `Value size cannot be larger than ${this.MAX_VALUE_SIZE}`, code: 'value_too_large' };
            }
            return args;
        },
    });

    setBatch_ = utils.make_driver_method(['items'], 'puter-kvstore', undefined, 'batchPut', {
        preprocess: (args) => {
            if ( !Array.isArray(args.items) || args.items.length === 0 ) {
                throw { message: 'Items are required', code: 'items_required' };
            }

            const normalizedItems = args.items.map((item) => {
                if ( ! isBatchSetItem(item) ) {
                    throw { message: 'Each item must include a key', code: 'invalid_item' };
                }

                const key = String(item.key);
                if ( key.length === 0 ) {
                    throw { message: 'Key cannot be undefined', code: 'key_undefined' };
                }
                if ( key.length > this.MAX_KEY_SIZE ) {
                    throw { message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' };
                }

                if ( item.value && item.value.length > this.MAX_VALUE_SIZE ) {
                    throw { message: `Value size cannot be larger than ${this.MAX_VALUE_SIZE}`, code: 'value_too_large' };
                }

                return {
                    key,
                    value: item.value,
                    ...(item.expireAt !== undefined ? { expireAt: item.expireAt } : {}),
                };
            });

            return {
                ...args,
                items: normalizedItems,
            };
        },
    });

    /**
     * Resolves to the value if the key exists, or `undefined` if the key does not exist. Rejects with an error on failure.
     */
    async get (...args) {
        if ( args.length === 1 && isObject(args[0]) ) {
            return await this.get_(args[0]);
        }

        const key = args[0];

        let optConfig;
        let success;
        let error;

        if ( isObject(args[1]) ) {
            optConfig = args[1];
            success = args[2];
            error = args[3];
        } else {
            success = args[1];
            error = args[2];
        }

        // Condition for gui boot cache
        if (
            typeof key === 'string' &&
            gui_cache_keys.includes(key) &&
            !optConfig &&
            this.gui_cached !== null
        ) {
            this.gui_cache_init && this.gui_cache_init.resolve();
            const cache = await this.gui_cached.promise;
            return cache[key];
        }

        // Normal get
        return await this.get_({ key, optConfig, success, error });
    }

    get_ = utils.make_driver_method(['key'], 'puter-kvstore', undefined, 'get', {
        preprocess: (args) => {
            // key size cannot be larger than MAX_KEY_SIZE
            if ( args.key.length > this.MAX_KEY_SIZE ) {
                throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
            }

            return args;
        },
        transform: (res) => {
            return res;
        },
    });

    incr = async (...args) => {
        let options = {};

        if ( args.length === 1 && isObject(args[0]) ) {
            options = { ...args[0] };
        } else {
            // arguments are required
            if ( !args || args.length === 0 ) {
                throw ({ message: 'Arguments are required', code: 'arguments_required' });
            }

            options.key = args[0];
            let amountOrMap = args[1];
            let optConfig = args[2];
            if ( isOptConfigShorthand(amountOrMap) && optConfig === undefined ) {
                optConfig = amountOrMap;
                amountOrMap = undefined;
            }
            options.pathAndAmountMap = !amountOrMap ? { '': 1 } : typeof amountOrMap === 'number' ? { '': amountOrMap } : amountOrMap;
            options.optConfig = optConfig;
        }

        // key size cannot be larger than MAX_KEY_SIZE
        if ( options.key.length > this.MAX_KEY_SIZE ) {
            throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
        }

        return utils.make_driver_method(['key'], 'puter-kvstore', undefined, 'incr').call(this, options);
    };

    decr = async (...args) => {
        let options = {};

        if ( args.length === 1 && isObject(args[0]) ) {
            options = { ...args[0] };
        } else {
            // arguments are required
            if ( !args || args.length === 0 ) {
                throw ({ message: 'Arguments are required', code: 'arguments_required' });
            }

            options.key = args[0];
            let amountOrMap = args[1];
            let optConfig = args[2];
            if ( isOptConfigShorthand(amountOrMap) && optConfig === undefined ) {
                optConfig = amountOrMap;
                amountOrMap = undefined;
            }
            options.pathAndAmountMap = !amountOrMap ? { '': 1 } : typeof amountOrMap === 'number' ? { '': amountOrMap } : amountOrMap;
            options.optConfig = optConfig;
        }

        // key size cannot be larger than MAX_KEY_SIZE
        if ( options.key.length > this.MAX_KEY_SIZE ) {
            throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
        }

        return utils.make_driver_method(['key'], 'puter-kvstore', undefined, 'decr').call(this, options);
    };

    add = async (...args) => {
        let options = {};

        if ( args.length === 1 && isObject(args[0]) ) {
            options = { ...args[0] };
        } else {
            // arguments are required
            if ( !args || args.length === 0 ) {
                throw ({ message: 'Arguments are required', code: 'arguments_required' });
            }

            options.key = args[0];

            let provided = args[1];
            let optConfig = args[2];
            if ( isOptConfigShorthand(provided) && optConfig === undefined ) {
                optConfig = provided;
                provided = undefined;
            }

            const isPathMap = provided && typeof provided === 'object' && !Array.isArray(provided);
            options.pathAndValueMap = provided === undefined ? { '': 1 } : isPathMap ? provided : { '': provided };
            options.optConfig = optConfig;
        }

        // key size cannot be larger than MAX_KEY_SIZE
        if ( options.key.length > this.MAX_KEY_SIZE ) {
            throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
        }

        return utils.make_driver_method(['key'], 'puter-kvstore', undefined, 'add').call(this, options);
    };

    remove = async (...args) => {
        if ( !args || args.length < 2 ) {
            throw ({ message: 'At least one path is required', code: 'arguments_required' });
        }

        const key = args[0];
        const paths = args.slice(1);
        let optConfig;

        if ( isObject(paths[paths.length - 1]) ) {
            optConfig = paths.pop();
        }

        if ( Array.isArray(paths[0]) && paths.length === 1 ) {
            throw ({ message: 'Paths must be provided as separate arguments', code: 'paths_invalid' });
        }

        if ( key === undefined || key === null ) {
            throw ({ message: 'Key cannot be undefined', code: 'key_undefined' });
        }

        if ( key.length > this.MAX_KEY_SIZE ) {
            throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
        }

        if ( paths.length === 0 ) {
            throw ({ message: 'At least one path is required', code: 'arguments_required' });
        }

        if ( paths.some((path) => typeof path !== 'string') ) {
            throw ({ message: 'All paths must be strings', code: 'paths_invalid' });
        }

        return utils.make_driver_method(['key', 'paths'], 'puter-kvstore', undefined, 'remove')
            .call(this, { key, paths, optConfig });
    };

    update = async (...args) => {
        if ( args.length === 1 && isObject(args[0]) ) {
            return await this.update_(args[0]);
        }

        const key = args[0];
        const pathAndValueMap = args[1];

        let ttl;
        let optConfig;
        let success;
        let error;

        const rest = args.slice(2);
        if ( typeof rest[0] === 'number' || rest[0] === null ) {
            ttl = rest.shift();
        }
        if ( rest[0] === undefined ) {
            rest.shift();
        }
        if ( isObject(rest[0]) ) {
            optConfig = rest.shift();
        }
        if ( typeof rest[0] === 'function' ) {
            success = rest.shift();
        }
        if ( typeof rest[0] === 'function' ) {
            error = rest.shift();
        }

        return await this.update_({ key, pathAndValueMap, ttl, optConfig, success, error });
    };

    update_ = utils.make_driver_method(['key', 'pathAndValueMap', 'ttl'], 'puter-kvstore', undefined, 'update', {
        preprocess: (args) => {
            if ( args.key === undefined || args.key === null ) {
                throw { message: 'Key cannot be undefined', code: 'key_undefined' };
            }
            if ( args.key.length > this.MAX_KEY_SIZE ) {
                throw { message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' };
            }
            if ( args.pathAndValueMap === undefined || args.pathAndValueMap === null || Array.isArray(args.pathAndValueMap) || typeof args.pathAndValueMap !== 'object' ) {
                throw { message: 'pathAndValueMap must be an object', code: 'path_map_invalid' };
            }
            if ( Object.keys(args.pathAndValueMap).length === 0 ) {
                throw { message: 'pathAndValueMap cannot be empty', code: 'path_map_invalid' };
            }
            if ( args.ttl !== undefined && args.ttl !== null ) {
                const ttl = Number(args.ttl);
                if ( Number.isNaN(ttl) ) {
                    throw { message: 'ttl must be a number', code: 'ttl_invalid' };
                }
                args.ttl = ttl;
            }
            return args;
        },
    });

    /**
     * Set a time to live (in seconds) on a key. After the time to live has expired, the key will be deleted.
     * Prefer this over expireAt if you want timestamp to be set by the server, to avoid issues with clock drift.
     * @param  {string} key - The key to set the expiration on.
     * @param  {number} ttl - The ttl
     * @memberof [KV]
     * @returns
     */
    expire = async (key, ttl, optConfig) => {
        let options = {};
        options.key = key;
        options.ttl = ttl;
        options.optConfig = optConfig;

        // key size cannot be larger than MAX_KEY_SIZE
        if ( options.key.length > this.MAX_KEY_SIZE ) {
            throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
        }

        return utils.make_driver_method(['key', 'ttl'], 'puter-kvstore', undefined, 'expire').call(this, options);
    };

    /**
     *
     * Set the expiration for a key as a UNIX timestamp (in seconds). After the time has passed, the key will be deleted.
     * Note that clients with a clock that is not in sync with the server may experience issues with this method.
     * @param  {string} key - The key to set the expiration on.
     * @param  {number} timestamp - The timestamp (in seconds since epoch) when the key will expire.
     * @memberof [KV]
     * @returns
     */
    expireAt = async (key, timestamp, optConfig) => {
        let options = {};
        options.key = key;
        options.timestamp = timestamp;
        options.optConfig = optConfig;
        // key size cannot be larger than MAX_KEY_SIZE
        if ( options.key.length > this.MAX_KEY_SIZE ) {
            throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
        }

        return utils.make_driver_method(['key', 'timestamp'], 'puter-kvstore', undefined, 'expireAt').call(this, options);
    };

    // resolves to 'true' on success, or rejects with an error on failure
    // will still resolve to 'true' if the key does not exist
    del = async (...args) => {
        if ( args.length === 1 && isObject(args[0]) ) {
            return await this.del_(args[0]);
        }

        const key = args[0];
        let optConfig;
        let success;
        let error;

        if ( isObject(args[1]) ) {
            optConfig = args[1];
            success = args[2];
            error = args[3];
        } else {
            success = args[1];
            error = args[2];
        }

        return await this.del_({ key, optConfig, success, error });
    };

    del_ = utils.make_driver_method(['key'], 'puter-kvstore', undefined, 'del', {
        preprocess: (args) => {
            // key size cannot be larger than this.MAX_KEY_SIZE
            if ( args.key.length > this.MAX_KEY_SIZE ) {
                throw ({ message: `Key size cannot be larger than ${this.MAX_KEY_SIZE}`, code: 'key_too_large' });
            }

            return args;
        },
    });

    list = async (...args) => {
        let options = {};
        let pattern;
        let returnValues = false;

        const isOptionsObject = args.length === 1 && args[0] && typeof args[0] === 'object' && !Array.isArray(args[0]);

        if ( isOptionsObject ) {
            const input = args[0];
            if ( typeof input.pattern === 'string' ) {
                pattern = input.pattern;
            }
            returnValues = !!input.returnValues;
            if ( isObject(input.optConfig) ) {
                options.optConfig = input.optConfig;
            } else if ( isOptConfigShorthand(input) ) {
                options.optConfig = input;
            }
            if ( input.limit !== undefined ) {
                options.limit = input.limit;
            }
            if ( input.cursor !== undefined ) {
                options.cursor = input.cursor;
            }
        } else {
            if ( isObject(args[1]) ) {
                options.optConfig = args[1];
            }

            if ( isObject(args[2]) ) {
                options.optConfig = args[2];
            }

            // list(true) or list(pattern, true) will return the key-value pairs
            if ( (args && args.length === 1 && args[0] === true) || (args && args.length === 2 && args[1] === true) ) {
                returnValues = true;
            }

            if ( args && args.length === 3 && args[1] === true ) {
                returnValues = true;
            }

            // list(pattern)
            // list(pattern, true)
            // list(pattern, optConfig)
            // list(pattern, true, optConfig)
            if ( (args && args.length === 1 && typeof args[0] === 'string') || (args && args.length === 2 && typeof args[0] === 'string' && args[1] === true) ) {
                pattern = args[0];
            }
            if ( args && args.length === 2 && typeof args[0] === 'string' && isObject(args[1]) ) {
                pattern = args[0];
            }
            if ( args && args.length === 3 && typeof args[0] === 'string' && args[1] === true ) {
                pattern = args[0];
            }
        }

        if ( ! returnValues ) {
            options.as = 'keys';
        }

        const normalizedPattern = normalizeListPattern(pattern);
        if ( normalizedPattern ) {
            options.pattern = normalizedPattern;
        }

        return utils.make_driver_method([], 'puter-kvstore', undefined, 'list').call(this, options);
    };

    // resolve to 'true' on success, or rejects with an error on failure
    // will still resolve to 'true' if there are no keys
    flush = async (...args) => {
        if ( args.length === 1 && isObject(args[0]) ) {
            const input = args[0];
            if (
                Object.prototype.hasOwnProperty.call(input, 'optConfig') ||
                Object.prototype.hasOwnProperty.call(input, 'success') ||
                Object.prototype.hasOwnProperty.call(input, 'error')
            ) {
                return await this.flush_(input);
            }

            return await this.flush_({ optConfig: input });
        }

        let optConfig;
        let success;
        let error;

        if ( isObject(args[0]) ) {
            optConfig = args[0];
            success = args[1];
            error = args[2];
        } else {
            success = args[0];
            error = args[1];
        }

        return await this.flush_({ optConfig, success, error });
    };

    flush_ = utils.make_driver_method([], 'puter-kvstore', undefined, 'flush');

    // clear is an alias for flush
    clear = this.flush;
}

function normalizeListPattern (pattern) {
    if ( typeof pattern !== 'string' ) {
        return undefined;
    }
    const trimmed = pattern.trim();
    if ( trimmed === '' ) {
        return undefined;
    }
    if ( trimmed.endsWith('*') ) {
        const prefix = trimmed.slice(0, -1);
        return prefix === '' ? undefined : prefix;
    }
    return trimmed;
}

export default KV;
